import numpy as np

def select_action(obs: np.ndarray) -> int:
    if obs[101] == 0:
        return 1  # FIRE to launch the ball

    ball_x = obs[99]
    ball_y = obs[101]
    paddle_x = obs[72]

    # Dynamic offset: aim further ahead when ball is higher (more time to adjust)
    if ball_y > 170:
        offset = -6   # ball low, aim slightly left to center
    elif ball_y > 130:
        offset = -3
    elif ball_y > 80:
        offset = 3
    else:
        offset = 10   # ball high, aim further right to compensate for travel

    target = ball_x + offset
    target = max(55, min(191, target))

    # Use a dead zone that shrinks as ball descends (tighter control near paddle)
    if ball_y < 100:
        dead_zone = 2
    elif ball_y < 160:
        dead_zone = 4
    else:
        dead_zone = 6

    if target < paddle_x - dead_zone:
        return 3  # LEFT
    elif target > paddle_x + dead_zone:
        return 2  # RIGHT
    return 0  # NOOP
